default(0.093) // CA default 9.3%\n  effectiveFederalRate Float  @default(0.22) // estimated\n  filingStatus         String @default(\"single\")\n\n  // Emergency fund\n  emergencyFundMonths Int @default(12) // 12 for H1B (vs 6 standard)\n\n  // Retirement\n  retirementAge         Int     @default(60)\n  lifeExpectancy        Int     @default(85)\n  includeSocialSecurity Boolean @default(false) // false for India nationals (no totalization)\n  estimatedSSBenefit    Float   @default(0) // monthly benefit, only if above = true\n\n  // FIRE\n  safeWithdrawalRate Float @default(0.04) // 4% rule\n\n  // Currency\n  usdToInrRate Float @default(83.5)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel VisaInfo {\n  id     String      @id @default(cuid())\n  userId String      @unique\n  user   UserProfile @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  visaType           String    @default(\"H1B\")\n  expiryDate         DateTime?\n  sponsorEmployer    String?\n  gcPetitionStage    String    @default(\"none\") // none | perm_in_progress | i140_filed | i140_approved | waiting_priority | i485_filed | approved\n  priorityDate       DateTime?\n  estimatedGcCost    Float     @default(25000) // $15k-$40k range\n  gcCostSaved        Float     @default(0)\n  lastH1bRenewalDate DateTime?\n  nextH1bRenewalDue  DateTime?\n  homeCountry        String    @default(\"India\")\n  passportExpiry     DateTime?\n  notes              String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// ─────────────────────────────────────────\n// INCOME\n// ─────────────────────────────────────────\n\nmodel IncomeSource {\n  id         String    @id @default(cuid())\n  name       String\n  type       String // salary | bonus | rsu | freelance | rental | interest | dividend | remittance_credit | other\n  amount     Float // gross amount\n  frequency  String    @default(\"monthly\") // monthly | annual | quarterly | one_time | biweekly\n  taxable    Boolean   @default(true)\n  growthRate Float     @default(0.05) // annual expected growth\n  scenario   String    @default(\"base\") // base | conservative | optimistic\n  isActive   Boolean   @default(true)\n  notes      String?\n  startDate  DateTime  @default(now())\n  endDate    DateTime?\n\n  // RSU specific\n  rsuVestingDate DateTime?\n  rsuShareCount  Float?\n  rsuFMVAtVest   Float?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// ─────────────────────────────────────────\n// EXPENSES\n// ─────────────────────────────────────────\n\nmodel ExpenseCategory {\n  id        String  @id @default(cuid())\n  name      String\n  icon      String?\n  color     String?\n  isH1b     Boolean @default(false) // H1B-specific category\n  isFixed   Boolean @default(false)\n  sortOrder Int     @default(0)\n\n  expenses Expense[]\n}\n\nmodel Expense {\n  id          String          @id @default(cuid())\n  name        String\n  categoryId  String\n  category    ExpenseCategory @relation(fields: [categoryId], references: [id])\n  amount      Float\n  frequency   String          @default(\"monthly\") // monthly | annual | quarterly | weekly | one_time\n  isFixed     Boolean         @default(false)\n  isEssential Boolean         @default(true)\n  notes       String?\n  isActive    Boolean         @default(true)\n  startDate   DateTime        @default(now())\n  endDate     DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// ─────────────────────────────────────────\n// ASSETS\n// ─────────────────────────────────────────\n\nmodel Asset {\n  id               String  @id @default(cuid())\n  name             String\n  type             String // checking | savings | 401k | roth_ira | hsa | brokerage | nre_account | nro_account | fcnr | crypto | vehicle | real_estate | other\n  balance          Float   @default(0)\n  currency         String  @default(\"USD\")\n  institution      String?\n  accountLast4     String?\n  isForeignAccount Boolean @default(false) // Triggers FBAR check\n  aprInterest      Float? // for interest-bearing accounts\n  notes            String?\n  isActive         Boolean @default(true)\n\n  // For retirement/investment accounts\n  contributionYTD Float? @default(0)\n  irsAnnualLimit  Float? // 401k: 23500, Roth IRA: 7000, HSA: 4300 (2025)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// ─────────────────────────────────────────\n// LIABILITIES / DEBT\n// ─────────────────────────────────────────\n\nmodel Liability {\n  id               String    @id @default(cuid())\n  name             String\n  type             String // student_loan | auto_loan | credit_card | mortgage | personal_loan | h1b_legal_fee | other\n  principalBalance Float\n  originalBalance  Float\n  interestRate     Float // annual % e.g. 0.065 = 6.5%\n  minimumPayment   Float\n  extraPayment     Float     @default(0)\n  paymentFrequency String    @default(\"monthly\")\n  startDate        DateTime?\n  payoffDate       DateTime? // calculated or target\n  lender           String?\n  notes            String?\n  isActive         Boolean   @default(true)\n\n  payments DebtPayment[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel DebtPayment {\n  id          String    @id @default(cuid())\n  liabilityId String\n  liability   Liability @relation(fields: [liabilityId], references: [id], onDelete: Cascade)\n  amount      Float\n  principal   Float\n  interest    Float\n  date        DateTime  @default(now())\n  notes       String?\n\n  createdAt DateTime @default(now())\n}\n\n// ─────────────────────────────────────────\n// INVESTMENTS\n// ─────────────────────────────────────────\n\nmodel Investment {\n  id               String  @id @default(cuid())\n  name             String\n  type             String // index_fund | etf | stock | mutual_fund | bond | reit | crypto | nre_fd | nro_fd | fcnr | savings_bond | other\n  accountType      String // taxable | traditional_401k | roth_401k | roth_ira | traditional_ira | hsa | nre | nro | fcnr | other\n  currentValue     Float   @default(0)\n  costBasis        Float   @default(0)\n  ticker           String? // optional stock/ETF ticker\n  allocation       Float   @default(0) // % of portfolio\n  currency         String  @default(\"USD\")\n  institution      String?\n  isForeignAccount Boolean @default(false)\n  notes            String?\n  isActive         Boolean @default(true)\n\n  contributions InvestmentContribution[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel InvestmentContribution {\n  id           String     @id @default(cuid())\n  investmentId String\n  investment   Investment @relation(fields: [investmentId], references: [id], onDelete: Cascade)\n  amount       Float\n  date         DateTime   @default(now())\n  type         String     @default(\"contribution\") // contribution | withdrawal | dividend | gain\n  notes        String?\n\n  createdAt DateTime @default(now())\n}\n\n// ─────────────────────────────────────────\n// GOALS\n// ─────────────────────────────────────────\n\nmodel Goal {\n  id                  String    @id @default(cuid())\n  name                String\n  type                String // emergency_fund | h1b_renewal | green_card | debt_payoff | home_down_payment | vehicle | wedding | travel | family_support | education | career_transition | sabbatical | child_planning | retirement | fire | custom\n  targetAmount        Float\n  currentAmount       Float     @default(0)\n  targetDate          DateTime?\n  priority            Int       @default(5) // 1-10, 10 = highest\n  monthlyContrib      Float     @default(0)\n  whyItMatters        String?\n  dependencies        String? // JSON array of goal IDs this depends on\n  status              String    @default(\"active\") // active | paused | completed | cancelled\n  confidenceScore     Float     @default(0) // 0-100, calculated\n  isInflationAdjusted Boolean   @default(true)\n  notes               String?\n  icon                String?\n  color               String?\n\n  milestones  GoalMilestone[]\n  allocations GoalAllocation[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel GoalMilestone {\n  id          String    @id @default(cuid())\n  goalId      String\n  goal        Goal      @relation(fields: [goalId], references: [id], onDelete: Cascade)\n  name        String\n  amount      Float\n  targetDate  DateTime?\n  isCompleted Boolean   @default(false)\n  completedAt DateTime?\n  notes       String?\n\n  createdAt DateTime @default(now())\n}\n\nmodel GoalAllocation {\n  id      String  @id @default(cuid())\n  goalId  String\n  goal    Goal    @relation(fields: [goalId], references: [id], onDelete: Cascade)\n  assetId String // references Asset.id (soft reference)\n  amount  Float\n  notes   String?\n\n  createdAt DateTime @default(now())\n}\n\n// ─────────────────────────────────────────\n// FINANCIAL SNAPSHOTS (monthly)\n// ─────────────────────────────────────────\n\nmodel FinancialSnapshot {\n  id    String @id @default(cuid())\n  month String @unique // YYYY-MM format e.g. \"2026-04\"\n\n  // Cash flow\n  totalIncomeGross Float @default(0)\n  totalIncomeNet   Float @default(0)\n  totalExpenses    Float @default(0)\n  freeCashFlow     Float @default(0)\n\n  // Balance sheet\n  totalAssets      Float @default(0)\n  totalLiabilities Float @default(0)\n  netWorth         Float @default(0)\n\n  // Derived rates\n  savingsRate       Float @default(0) // %\n  investmentRate    Float @default(0) // %\n  debtBurdenRatio   Float @default(0) // %\n  fixedExpenseRatio Float @default(0) // %\n\n  // Emergency fund\n  liquidAssets        Float @default(0)\n  emergencyFundMonths Float @default(0)\n  emergencyFundTarget Float @default(0)\n\n  // Scores (0-100)\n  healthScore          Float @default(0)\n  futureReadinessScore Float @default(